func TermFold[S any, R any](t Term[S], cs TermCases[S, R]) R {
	switch m := any(t).(type) {
	case Bool:
		return cs.Bool(m.Value)
	case BoolSymbol:
		return cs.BoolSymbol(m.ID, m.Name)
	case BooleanVariable:
		return cs.BooleanVariable(m.ID)
	case NegatedBooleanVariable:
		return cs.NegatedBooleanVariable(m.ID)
	case BooleanClause:
		return cs.BooleanClause(m.Literals)
	case BooleanCNF:
		return cs.BooleanCNF(m.Literals, m.ClauseEnds)
	case Not:
		return cs.Not(m.Value)
	case And:
		return cs.And(m.Values)
	case Or:
		return cs.Or(m.Values)
	case Implies:
		return cs.Implies(m.Left, m.Right)
	case Iff:
		return cs.Iff(m.Left, m.Right)
	case If[S]:
		return cs.If(m.Condition, m.Then, m.Else)
	case Equal:
		return cs.Equal(m.Left, m.Right)
	case Integer:
		return cs.Integer(m.Value)
	case integerExact[S]:
		return cs.integerExact(m.value)
	case IntSymbol:
		return cs.IntSymbol(m.ID, m.Name)
	case integerVariable[S]:
		return cs.integerVariable(m.iD)
	case Add:
		return cs.Add(m.Values)
	case Subtract:
		return cs.Subtract(m.Left, m.Right)
	case IntegerScale:
		return cs.IntegerScale(m.Coefficient, m.Value)
	case IntegerDiv:
		return cs.IntegerDiv(m.Dividend, m.Divisor)
	case IntegerMod:
		return cs.IntegerMod(m.Dividend, m.Divisor)
	case LessEqual:
		return cs.LessEqual(m.Left, m.Right)
	case Less:
		return cs.Less(m.Left, m.Right)
	case Real:
		return cs.Real(m.Value)
	case RealSymbol:
		return cs.RealSymbol(m.ID, m.Name)
	case RealAdd:
		return cs.RealAdd(m.Values)
	case RealSubtract:
		return cs.RealSubtract(m.Left, m.Right)
	case RealScale:
		return cs.RealScale(m.Coefficient, m.Value)
	case RealLessEqual:
		return cs.RealLessEqual(m.Left, m.Right)
	case RealLess:
		return cs.RealLess(m.Left, m.Right)
	case uninterpretedValue[S]:
		return cs.uninterpretedValue(m.sortID, m.iD, m.name)
	case unaryApplication[S]:
		return cs.unaryApplication(m.function, m.argument)
	case binaryApplication[S]:
		return cs.binaryApplication(m.function, m.first, m.second)
	case sortedUnaryApplication[S]:
		return cs.sortedUnaryApplication(m.function, m.argument, m.rangeKind)
	case sortedBinaryApplication[S]:
		return cs.sortedBinaryApplication(m.function, m.first, m.second, m.rangeKind)
	case bitVector[S]:
		return cs.bitVector(m.value)
	case bitVectorSymbol[S]:
		return cs.bitVectorSymbol(m.width, m.iD, m.name)
	case bitVectorNot[S]:
		return cs.bitVectorNot(m.value)
	case bitVectorAnd[S]:
		return cs.bitVectorAnd(m.left, m.right)
	case bitVectorOr[S]:
		return cs.bitVectorOr(m.left, m.right)
	case bitVectorXor[S]:
		return cs.bitVectorXor(m.left, m.right)
	case bitVectorAdd[S]:
		return cs.bitVectorAdd(m.left, m.right)
	case bitVectorSub[S]:
		return cs.bitVectorSub(m.left, m.right)
	case bitVectorMul[S]:
		return cs.bitVectorMul(m.left, m.right)
	case bitVectorShiftLeft[S]:
		return cs.bitVectorShiftLeft(m.value, m.amount)
	case bitVectorLogicalShiftRight[S]:
		return cs.bitVectorLogicalShiftRight(m.value, m.amount)
	case bitVectorArithmeticShiftRight[S]:
		return cs.bitVectorArithmeticShiftRight(m.value, m.amount)
	case bitVectorUnsignedDiv[S]:
		return cs.bitVectorUnsignedDiv(m.left, m.right)
	case bitVectorUnsignedRem[S]:
		return cs.bitVectorUnsignedRem(m.left, m.right)
	case bitVectorSignedDiv[S]:
		return cs.bitVectorSignedDiv(m.left, m.right)
	case bitVectorSignedRem[S]:
		return cs.bitVectorSignedRem(m.left, m.right)
	case bitVectorConcat[S]:
		return cs.bitVectorConcat(m.first, m.second, m.firstWidth, m.secondWidth)
	case bitVectorExtract[S]:
		return cs.bitVectorExtract(m.value, m.high, m.low)
	case bitVectorZeroExtend[S]:
		return cs.bitVectorZeroExtend(m.value, m.additional)
	case bitVectorSignExtend[S]:
		return cs.bitVectorSignExtend(m.value, m.additional)
	case bitVectorRotateLeft[S]:
		return cs.bitVectorRotateLeft(m.value, m.amount)
	case bitVectorRotateRight[S]:
		return cs.bitVectorRotateRight(m.value, m.amount)
	case bitVectorRepeat[S]:
		return cs.bitVectorRepeat(m.value, m.count)
	case bitVectorUnsignedLess[S]:
		return cs.bitVectorUnsignedLess(m.left, m.right, m.orEqual)
	case bitVectorSignedLess[S]:
		return cs.bitVectorSignedLess(m.left, m.right, m.orEqual)
	case bitVectorUnsignedAddOverflow[S]:
		return cs.bitVectorUnsignedAddOverflow(m.left, m.right)
	case bitVectorSignedAddOverflow[S]:
		return cs.bitVectorSignedAddOverflow(m.left, m.right)
	case bitVectorUnsignedSubOverflow[S]:
		return cs.bitVectorUnsignedSubOverflow(m.left, m.right)
	case bitVectorSignedSubOverflow[S]:
		return cs.bitVectorSignedSubOverflow(m.left, m.right)
	case bitVectorUnsignedMulOverflow[S]:
		return cs.bitVectorUnsignedMulOverflow(m.left, m.right)
	case bitVectorSignedMulOverflow[S]:
		return cs.bitVectorSignedMulOverflow(m.left, m.right)
	case bitVectorSignedDivOverflow[S]:
		return cs.bitVectorSignedDivOverflow(m.left, m.right)
	case bitVectorNegOverflow[S]:
		return cs.bitVectorNegOverflow(m.value)
	case bitVectorToInteger[S]:
		return cs.bitVectorToInteger(m.value, m.signed)
	case integerToBitVector[S]:
		return cs.integerToBitVector(m.value, m.width)
	case arraySymbol[S]:
		return cs.arraySymbol(m.iD, m.name)
	case constantArray[S]:
		return cs.constantArray(m.defaultValue)
	case arraySelect[S]:
		return cs.arraySelect(m.array, m.index)
	case arrayStore[S]:
		return cs.arrayStore(m.array, m.index, m.value)
	case arrayReadInteger[S]:
		return cs.arrayReadInteger(m.arrayID, m.index)
	case arrayStoreReadInteger[S]:
		return cs.arrayStoreReadInteger(m.arrayID, m.storeIndexID, m.readIndexID, m.value)
	default:
		panic("goplus: impossible enum value in TermFold")
	}
}

