// AnyTermEqOverrides carries optional per-variant hooks for AnyTermEqualWith.
// A hook returning handled=false falls through to the derived comparison.
type AnyTermEqOverrides struct {
	SomeBool func(x, y SomeBool) (eq, handled bool)
	SomeInt  func(x, y SomeInt) (eq, handled bool)
	SomeReal func(x, y SomeReal) (eq, handled bool)
}

// AnyTermEqualWith reports structural equality of a and b under ov.
func AnyTermEqualWith(a, b AnyTerm, ov AnyTermEqOverrides) bool {
	if a == nil || b == nil {
		return a == nil && b == nil
	}
	switch x := any(a).(type) {
	case SomeBool:
		y, ok := any(b).(SomeBool)
		if !ok {
			return false
		}
		if ov.SomeBool != nil {
			if eq, handled := ov.SomeBool(x, y); handled {
				return eq
			}
		}
		if x.Value != y.Value {
			return false
		}
		return true
	case SomeInt:
		y, ok := any(b).(SomeInt)
		if !ok {
			return false
		}
		if ov.SomeInt != nil {
			if eq, handled := ov.SomeInt(x, y); handled {
				return eq
			}
		}
		if x.Value != y.Value {
			return false
		}
		return true
	case SomeReal:
		y, ok := any(b).(SomeReal)
		if !ok {
			return false
		}
		if ov.SomeReal != nil {
			if eq, handled := ov.SomeReal(x, y); handled {
				return eq
			}
		}
		if x.Value != y.Value {
			return false
		}
		return true
	}
	return false
}

// AnyTermEqual reports structural equality of a and b.
func AnyTermEqual(a, b AnyTerm) bool {
	return AnyTermEqualWith(a, b, AnyTermEqOverrides{})
}

